UPDATE vocabulario SET concepto_ingles = 'small cute 3D analog wall clock showing 10:00 AM with a bright morning sun symbol next to it' WHERE palabra_aleman IN ('der Vormittag', 'am Vormittag');
UPDATE vocabulario SET concepto_ingles = 'small cute 3D analog wall clock showing exactly 12:00 noon with a bright sun directly overhead' WHERE palabra_aleman IN ('der Mittag', 'am Mittag');
UPDATE vocabulario SET concepto_ingles = 'small cute 3D analog wall clock showing 4:00 PM with a setting sun symbol next to it' WHERE palabra_aleman IN ('der Nachmittag', 'am Nachmittag');
